codeExamples.code:
/* Default: borders are separate with gaps */
.table-separate {
  border-collapse: separate;
  border-spacing: 4px;
}
.table-separate th,
.table-separate td {
  border: 1px solid #ccc;
  padding: 8px;
}

/* Collapsed: borders merge into single lines */
.table-collapsed {
  border-collapse: collapse;
}
.table-collapsed th,
.table-collapsed td {
  border: 1px solid #ccc;
  padding: 8px;
}

.styled-table {
  border-collapse: collapse;
  width: 100%;
}

.styled-table th,
.styled-table td {
  padding: 12px 16px;
  text-align: left;
  border-bottom: 1px solid #e5e7eb;
}

.styled-table thead th {
  background-color: #f9fafb;
  font-weight: 600;
  color: #374151;
  border-bottom: 2px solid #d1d5db;
}

/* Zebra striping on tbody rows only */
.styled-table tbody tr:nth-child(even) {
  background-color: #f9fafb;
}

/* Hover highlight */
.styled-table tbody tr:hover {
  background-color: #eff6ff;
}

/* Wrapper enables horizontal scroll on small screens */
.table-container {
  width: 100%;
  overflow-x: auto;
}

.responsive-table {
  border-collapse: collapse;
  width: 100%;
  min-width: 600px;
}

.responsive-table th,
.responsive-table td {
  padding: 10px 14px;
  white-space: nowrap;
  border: 1px solid #e5e7eb;
}

.sticky-table-container {
  max-height: 400px;
  overflow-y: auto;
}

.sticky-table {
  border-collapse: collapse;
  width: 100%;
}

.sticky-table thead th {
  position: sticky;
  top: 0;
  background-color: #1f2937;
  color: white;
  padding: 12px 16px;
  z-index: 1;
}

.sticky-table td {
  padding: 10px 16px;
  border-bottom: 1px solid #e5e7eb;
}

